import org.json.JSONArray
import groovy.json.JsonOutput

// get the host, credentials, and mgmt station baseurl from the device property table
hostname = hostProps.get("system.hostname");
userid = hostProps.get("tegile.user");
passwd = hostProps.get("tegile.pass");
base_url = "https://" + hostname;
//create auth Base64 encryption
auth_raw = userid + ":" + passwd
auth = auth_raw.bytes.encodeBase64().toString()

poolArray=[]

// construct the full endpoint url
endpoint_url = base_url + "/zebi/api/v2/listPools"; //LIST POOLS
method = "get"
get_pools = APIrequest(endpoint_url,auth,method)

if (get_pools != 404){
	// iterate over the json_object 
	for (int i=0; i<get_pools.length();i++){
		JSONObject obj = get_pools.get(i);

		pool_name = obj.getString("name");

		poolArray.add(pool_name) //store the pool in the poolArray (to further iterate over it)
	}

	//iterate over the newly built pool(s) array
	poolArray.each{
		pool_iterate=it

		//query the projects for the Pool in question
		endpoint_url = base_url + "/zebi/api/v2/listProjects"; //LIST POOLS
		method = "post"
		pool_name='"'+pool_iterate+'", true'
		post_reply=false
		get_projects_withinPool = APIrequest(endpoint_url,auth,method,pool_name,post_reply)

		for (int i=0; i<get_projects_withinPool.length();i++){
			JSONObject obj1 = get_projects_withinPool.get(i);

			projectName = obj1["name"]
			projectName_wildvalue = SpecialCharacterCheck(projectName)

			//get LUN/Volume details (within each project)
			endpoint_url = base_url + "/zebi/api/v2/listVolumes"; //LIST POOLS
			method = "post"
			pool_name='"'+pool_iterate+'", "'+projectName+'", true'
			post_reply=false
			get_project_luns = APIrequest(endpoint_url,auth,method,pool_name,post_reply)		

			for (int z=0; z<get_project_luns.length();z++){
				JSONObject obj2 = get_project_luns.get(z);

				lun_name = obj2["name"]
				lun_name_wildvalue = SpecialCharacterCheck(lun_name)

				lun_id = obj2["luId"]
				lun_datasetPath = obj2["datasetPath"]

				//get LUN/Volume details
				endpoint_url = base_url + "/zebi/api/v2/getVolume"; //LIST POOLS
				method = "post"
				pool_name='"'+pool_iterate+'/Local/'+projectName+'/'+lun_name+'"'
				post_reply=true
				get_lun_details = APIrequest(endpoint_url,auth,method,pool_name,post_reply)

				for (int y=0; y<get_lun_details.length();y++){
					JSONObject obj3 = get_lun_details.get(y);

					volSize = obj3["volSize"]
					try{
						usedSize = obj3["usedSize"]
					}catch(Exception ex1){
						usedSize = null
					}
					readonly_raw = obj3["readonly"] //on or off (needs to be converted to 0/1)
					if(readonly_raw.contains("on")){readonly=1}else{readonly=0}
					reservationInByte = obj3["reservationInByte"]

					println lun_name_wildvalue+".volSize="+volSize
					println lun_name_wildvalue+".usedSize="+usedSize
					println lun_name_wildvalue+".readonly="+readonly
					println lun_name_wildvalue+".reservationInByte="+reservationInByte
				}

				//get LUN/Volume Status details
				endpoint_url = base_url + "/zebi/api/v2/listLunsById"; //LIST POOLS
				method = "post"
				pool_name='["'+lun_id+'"]'
				post_reply=false
				get_lun_status = APIrequest(endpoint_url,auth,method,pool_name,post_reply)

				for (int x=0; x<get_lun_status.length();x++){
					JSONObject obj4 = get_lun_status.get(x);

					operationalStatus = obj4["operationalStatus"]
					accessState = obj4["accessState"]

					println lun_name_wildvalue+".operationalStatus="+operationalStatus
					println lun_name_wildvalue+".accessState="+accessState
				}

				//get LUN/Volume Data Stats
				endpoint_url = base_url + "/zebi/api/v2/getOneMinuteDataAnalyticsHistory"; //LIST POOLS
				method = "post"
				pool_name='["'+pool_iterate+'/'+projectName+'/'+lun_name+'"],null,null'
				post_reply=false
				get_lun_datastats = APIrequest(endpoint_url,auth,method,pool_name,post_reply)

				for (int j=0; j<get_lun_datastats.length();j++){
					JSONObject obj5 = get_lun_datastats.get(j);

					Read_MBps = obj5["averages"]["Read_MBps"]
					Write_MBps = obj5["averages"]["Write_MBps"]
					Total_MBps = obj5["averages"]["Total_MBps"]
					Read_Ops = obj5["averages"]["Read_Ops"]
					Write_Ops = obj5["averages"]["Write_Ops"]
					Total_Ops = obj5["averages"]["Total_Ops"]
					Read_Latency = obj5["averages"]["Read_Latency"]
					Write_Latency = obj5["averages"]["Write_Latency"]
					Average_Latency = obj5["averages"]["Average_Latency"]

					println lun_name_wildvalue+".Read_MBps="+Read_MBps
					println lun_name_wildvalue+".Write_MBps="+Write_MBps
					println lun_name_wildvalue+".Total_MBps="+Total_MBps
					println lun_name_wildvalue+".Read_Ops="+Read_Ops
					println lun_name_wildvalue+".Write_Ops="+Write_Ops
					println lun_name_wildvalue+".Total_Ops="+Total_Ops
					println lun_name_wildvalue+".Read_Latency="+Read_Latency
					println lun_name_wildvalue+".Write_Latency="+Write_Latency
					println lun_name_wildvalue+".Average_Latency="+Average_Latency
				}
			}
		}
	}
	return(0);
}

